import { Outlet } from "react-router-dom";

function IdentificationPage() {


  return (
    <div style={{display:"flex", width:"100%", height:"100%"}}>
      <div style={{
        width:"50%",
        height:"50%",
      }}>
        
      </div>
      <div style={{
      position: "absolute", 
      display:"flex",
      flexDirection: "column",
      right: "3%", 
      top: "50%", 
      transform: "translateY(-50%)",
      maxWidth: "720px",
      maxHeight: "745px",
      alignItems: "center",
      width: "100%",
      height: "100%",
      
      }}>
        <Outlet/>
      </div>
    </div>
  );
}

export default IdentificationPage;
